request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?node ?name ?type WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?node tai:belongsTo ?choreo .
  { ?node a bboExt:StartEvent . }
  UNION { ?node a bboExt:EndEvent . }
  UNION { ?node a bboExt:ChoreographyTask . }
  UNION { ?node a bboExt:ExclusiveGateway . }
  UNION { ?node a bboExt:EventBasedGateway . }
  ?node a ?type .
  OPTIONAL { ?node bbo:name ?name . }
}
ORDER BY ?type ?name
